import{_ as o,r as n,o as i,c as a,b as e,d as t,e as r,a as c}from"./app-2a089349.js";const l={},p=e("h1",{id:"restricted-by-active-subscription",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#restricted-by-active-subscription","aria-hidden":"true"},"#"),t(" Restricted by Active Subscription")],-1),d=e("h2",{id:"overview",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#overview","aria-hidden":"true"},"#"),t(" Overview")],-1),h=e("p",null,[t("We are introducing the latest enhancement to our Stripe restriction feature – the "),e("strong",null,'"Active Subscription Only'),t('" option. With this update, users who are subscribed to a plan or pricing tier but have an inactive subscription will no longer have access to restricted pages, posts, taxonomies, media, or tags. The restriction is specifically tied to an active subscription status.')],-1),g=e("p",null,'By default, irrespective of their subscription status (active, inactive, or canceled), users who have subscribed to a plan or pricing tier can view restricted pages through Stripe. However, the newly added "Active Subscription Only" option allows you to enforce restrictions exclusively for users with an active subscription, ensuring more precise control over access to your content.',-1),u={href:"https://ultimatemember.github.io/docs-v3/um-stripe/article/1805-stripe-content-restriction.html",target:"_blank",rel:"noopener noreferrer"},b=c('<p>To enable the <strong>Active Subscription Only</strong> feature, go to the content you want to restrict and allow access to only users who have active subscriptions.</p><ol><li>Go to <strong>wp-admin &gt; Pages</strong> and either add a new page or edit an existing one. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2a05a270765339befc5c5/file-dIjgl6jnxF.png" alt=""></li><li>In the page settings, scroll down to <strong>&#39;Ultimate Member: Content Restriction&#39;</strong> and activate the <strong>&#39;Restrict Access to this post&#39;</strong> option.</li><li>From the <strong>&quot;Who can access this post?&quot;</strong> dropdown, select <strong>&#39;Logged in users.&#39;</strong> The Stripe restriction feature will only appear if you choose &#39;logged-in users.&#39;</li><li>If you wish to implement content restrictions based on Stripe plans, enable the <strong>&#39;Restrict Access by Stripe Plans&#39;</strong> option. Enabling this will reveal additional settings for Stripe content restrictions.</li><li>To restrict access to users with an active subscription only, enable the <strong>&#39;Active Subscription Only&#39;</strong> setting. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2aa4030c1875e8e0673ef/file-xbRQf322iL.png" alt=""></li></ol><h3 id="here-is-an-example-of-how-the-functionality-works" tabindex="-1"><a class="header-anchor" href="#here-is-an-example-of-how-the-functionality-works" aria-hidden="true">#</a> Here is an example of how the functionality works:</h3><p>To explain how the functionality works, we have created different user roles in wp-admin&gt;Ultimate Member&gt; User Roles. These roles include <strong>Active</strong> <strong>Subscriber</strong>, <strong>Canceled Subscriber</strong>, <strong>Past Due Subscriber</strong>, <strong>Paused Subscriber</strong>, <strong>Trialing Subscriber</strong>, and <strong>Unpaid Subscriber</strong>.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2bb4030c1875e8e06740b/file-ST2qWXYyln.png" alt=""></p><p>We have also set these roles in <strong>wp-admin&gt;Ultimate Member&gt; Stripe Plans for the &#39;Basic Plan - $9.99/month&#39;</strong> that we have imported.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2bfdc12800975164519c7/file-vsvrMkyBRr.png" alt=""></p><p>We have created a page titled <strong>&quot;Blog&quot;</strong> and configured its content restriction settings as explained in the section above.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2c929270765339befc5fd/file-uYvFp2naKQ.png" alt=""></p><p>Both users Jane Doe and Jay Hugh are subscribed to the Basic Plan and have an <strong>active subscription</strong>, making them both <strong>Active Subscribers</strong>.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2c71752a6af5def3c8d0d/file-CszdNRPJ5v.png" alt=""></p><p>Therefore, they can access and view the contents on the Blog page.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2cfe112800975164519d0/file-o4RlwZUnxA.png" alt=""></p><p>When Jane Doe pauses her subscription, her subscription status changes to <strong>Paused</strong> and her role becomes <strong>Paused Subscriber</strong>. As a result, she no longer has access to the Blog page.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b2d7d952a6af5def3c8d1d/file-VRKoeUAWUK.png" alt=""></p>',15);function m(f,v){const s=n("ExternalLinkIcon");return i(),a("div",null,[p,d,h,g,e("p",null,[t("We recommend reading the "),e("a",u,[t("Stripe Content Restriction article"),r(s)]),t(" first to understand this document better.")]),b])}const y=o(l,[["render",m],["__file","1895-restricted-by-active-subscription.html.vue"]]);export{y as default};
